from __future__ import annotations

import enum
import logging
import ssl
import time
import types
import typing

import h11

from .._backends.base import NetworkStream
from .._exceptions import (
    ConnectionNotAvailable,
    LocalProtocolError,
    RemoteProtocolError,
    WriteError,
    map_exceptions,
)
from .._models import Origin, Request, Response
from .._synchronization import Lock, ShieldCancellation
from .._trace import Trace
from .interfaces import ConnectionInterface

logger = logging.getLogger("httpcore.http11")


# A subset of `h11.Event` types supported by `_send_event`
H11SendEvent = typing.Union[
    h11.Request,
    h11.Data,
    h11.EndOfMessage,
]


class HTTPConnectionState(enum.IntEnum):
    NEW = 0
    ACTIVE = 1
    IDLE = 2
    CLOSED = 3


class HTTP11Connection(ConnectionInterface):
    READ_NUM_BYTES = 64 * 1024
    MAX_INCOMPLETE_EVENT_SIZE = 100 * 1024

    def __init__(
        self,
        origin: Origin,
        stream: NetworkStream,
        keepalive_expiry: float | None = None,
    ) -> None:
        """
        Initialize an HTTP/1.1 connection.

        Parameters:
        - origin: The Origin this connection is connected to.
        - stream: The underlying network stream.
        - keepalive_expiry: Optional keep-alive expiry time in seconds.
        """
        self._origin = origin
        self._network_stream = stream
        self._keepalive_expiry: float | None = keepalive_expiry
        self._expire_at: float | None = None
        self._state = HTTPConnectionState.NEW
        self._state_lock = Lock()
        self._request_count = 0
        self._h11_state = h11.Connection(
            our_role=h11.CLIENT,
            max_incomplete_event_size=self.MAX_INCOMPLETE_EVENT_SIZE,
        )

    def handle_request(self, request: Request) -> Response:
        """
        Handle a synchronous HTTP request on this connection and return a Response.

        This manages state transitions and delegates to internal helper methods
        to send the request and receive the response.
        """
        if not self.can_handle_request(request.url.origin):
            raise RuntimeError(
                f"Attempted to send request to {request.url.origin} on connection "
                f"to {self._origin}"
            )

        with self._state_lock:
            if self._state in (HTTPConnectionState.NEW, HTTPConnectionState.IDLE):
                self._request_count += 1
                self._state = HTTPConnectionState.ACTIVE
                self._expire_at = None
            else:
                raise ConnectionNotAvailable()

        try:
            kwargs = {"request": request}
            try:
                with Trace(
                    "send_request_headers", logger, request, kwargs
                ) as trace:
                    self._send_request_headers(**kwargs)
                with Trace("send_request_body", logger, request, kwargs) as trace:
                    self._send_request_body(**kwargs)
            except WriteError:
                # If we get a write error while we're writing the request,
                # then we supress this error and move on to attempting to
                # read the response. Servers can sometimes close the request
                # pre-emptively and then respond with a well formed HTTP
                # error response.
                pass

            with Trace(
                "receive_response_headers", logger, request, kwargs
            ) as trace:
                (
                    http_version,
                    status,
                    reason_phrase,
                    headers,
                    trailing_data,
                ) = self._receive_response_headers(**kwargs)
                trace.return_value = (
                    http_version,
                    status,
                    reason_phrase,
                    headers,
                )

            network_stream: typing.Union[NetworkStream, "HTTP11UpgradeStream"] = self._network_stream

            # CONNECT or Upgrade request
            if (status == 101) or (
                (request.method == b"CONNECT") and (200 <= status < 300)
            ):
                network_stream = HTTP11UpgradeStream(network_stream, trailing_data)

            return Response(
                status=status,
                headers=headers,
                content=HTTP11ConnectionByteStream(self, request),
                extensions={
                    "http_version": http_version,
                    "reason_phrase": reason_phrase,
                    "network_stream": network_stream,
                },
            )
        finally:
            # If the response wasn't consumed by the client, then ensure
            # the connection eventually transitions out of ACTIVE.
            with self._state_lock:
                if self._state == HTTPConnectionState.ACTIVE:
                    # If there's no keepalive setting, close immediately.
                    if self._keepalive_expiry is None:
                        self._state = HTTPConnectionState.CLOSED
                    else:
                        self._state = HTTPConnectionState.IDLE
                        self._expire_at = time.time() + self._keepalive_expiry

    def _send_request_headers(self, request: Request) -> None:
        """
        Send the request headers for a request.

        This method prepares an h11.Request event (or equivalent) and sends
        the serialized bytes on the network stream.
        """
        raise NotImplementedError("Request header sending is not implemented in this shim.")

    def _send_request_body(self, request: Request) -> None:
        """
        Send the request body for a request.

        This method should send body bytes (if any) and an EndOfMessage event.
        """
        raise NotImplementedError("Request body sending is not implemented in this shim.")

    def _send_event(self, event: H11SendEvent) -> None:
        """
        Send a single h11 event to the remote side.

        Event serialization is handled by h11, with the resulting bytes written
        to the underlying network stream.
        """
        raise NotImplementedError("Event sending is not implemented in this shim.")

    def _receive_response_headers(
        self, request: Request
    ) -> typing.Tuple[str, int, str, list[tuple[bytes, bytes]], bytes]:
        """
        Receive the response headers for a request.

        Should return a tuple of:
        (http_version, status_code, reason_phrase, headers, trailing_data)

        'trailing_data' contains any bytes read from the network that belong
        to the response body (or upgrade data) and should be preserved.
        """
        raise NotImplementedError("Response header receiving is not implemented in this shim.")

    def _receive_response_body(self, request: Request) -> typing.Iterator[bytes]:
        """
        Receive the response body for a request.

        This should yield chunks of body bytes until the response end is
        reached.
        """
        raise NotImplementedError("Response body receiving is not implemented in this shim.")

    def _receive_event(self) -> h11.Event:
        """
        Receive and return a single h11 event from the network.

        This involves reading bytes from the network, feeding them to h11,
        and returning the next available event.
        """
        raise NotImplementedError("Event receiving is not implemented in this shim.")

    def _response_closed(self, request: Request) -> None:
        """
        Handle the response being closed by the consumer.

        This will transition the connection state appropriately and mark the
        connection as expired when necessary.
        """
        # Transition to IDLE or CLOSED depending on keepalive settings.
        with self._state_lock:
            if self._state == HTTPConnectionState.ACTIVE:
                if self._keepalive_expiry is None:
                    self._state = HTTPConnectionState.CLOSED
                else:
                    self._state = HTTPConnectionState.IDLE
                    self._expire_at = time.time() + self._keepalive_expiry

    def close(self) -> None:
        """
        Close the underlying connection promptly and mark as closed.
        """
        with self._state_lock:
            self._state = HTTPConnectionState.CLOSED
        try:
            # Attempt to close the network stream if it supports close().
            close_method = getattr(self._network_stream, "close", None)
            if callable(close_method):
                close_method()
        except Exception:
            logger.exception("Error while closing network stream")

    def can_handle_request(self, origin: Origin) -> bool:
        """
        Return True if this connection can handle a request for the given origin.

        This checks that the connection is to the same origin, and that it's
        not currently active or closed.
        """
        if origin != self._origin:
            return False
        return self._state in (HTTPConnectionState.NEW, HTTPConnectionState.IDLE)

    def is_available(self) -> bool:
        """
        Return True if the connection is available for use.

        Available means not ACTIVE and not CLOSED.
        """
        return self._state in (HTTPConnectionState.NEW, HTTPConnectionState.IDLE)

    def has_expired(self) -> bool:
        """
        Return True if the connection's keep-alive timeout has expired.
        """
        if self._expire_at is None:
            return False
        return time.time() >= self._expire_at

    def is_idle(self) -> bool:
        """
        Return True if the connection is currently idle.
        """
        return self._state == HTTPConnectionState.IDLE

    def is_closed(self) -> bool:
        """
        Return True if the connection has been closed.
        """
        return self._state == HTTPConnectionState.CLOSED

    def info(self) -> dict:
        """
        Return diagnostic information about the connection.
        """
        return {
            "origin": self._origin,
            "state": int(self._state),
            "request_count": self._request_count,
            "expire_at": self._expire_at,
        }

    def __repr__(self) -> str:
        """
        Return a representation for debugging purposes.
        """
        return f"<HTTP11Connection [{self._origin!r}] state={self._state.name}>"

    def __enter__(self) -> "HTTP11Connection":
        """
        Enter the runtime context related to this object.

        Returns self for use with the 'with' statement.
        """
        return self

    def __exit__(self, exc_type, exc, tb) -> None:
        """
        Exit the runtime context and close the connection.
        """
        self.close()


class HTTP11ConnectionByteStream:
    def __init__(self, connection: HTTP11Connection, request: Request) -> None:
        """
        A synchronous byte stream for a response body.

        This object is an iterable yielding byte chunks for the response body.
        """
        self._connection = connection
        self._request = request
        self._closed = False

    def __iter__(self) -> typing.Iterator[bytes]:
        """
        Iterate over the response body, yielding bytes until complete.
        """
        if self._closed:
            return
        # Delegate to the connection's response body receiver.
        for chunk in self._connection._receive_response_body(self._request):
            yield chunk
        self._closed = True

    def close(self) -> None:
        """
        Close the byte stream, notifying the connection that the response has been closed.
        """
        if not self._closed:
            self._closed = True
            try:
                self._connection._response_closed(self._request)
            except Exception:
                logger.exception("Error while closing response stream")


class HTTP11UpgradeStream:
    def __init__(self, network_stream: NetworkStream, trailing_data: bytes) -> None:
        """
        A wrapper around the raw network stream for connection upgrades.

        It preserves any trailing data that was read from the network as part
        of the response headers parsing.
        """
        self._network_stream = network_stream
        self._trailing_data = trailing_data or b""
        self._trailing_view = memoryview(self._trailing_data)
        self._trailing_pos = 0

    def read(self, max_bytes: int | None = None) -> bytes:
        """
        Read bytes from the upgrade stream. Consumes any preserved trailing data
        first, then reads from the underlying network stream.
        """
        # Serve from trailing data if present.
        if self._trailing_pos < len(self._trailing_view):
            if max_bytes is None:
                start = self._trailing_pos
                self._trailing_pos = len(self._trailing_view)
                return bytes(self._trailing_view[start:])
            else:
                start = self._trailing_pos
                end = min(start + max_bytes, len(self._trailing_view))
                self._trailing_pos = end
                return bytes(self._trailing_view[start:end])
        # Fallback to the underlying stream's read method if available.
        read_method = getattr(self._network_stream, "read", None)
        if callable(read_method):
            if max_bytes is None:
                # Read as much as the underlying stream provides.
                return read_method()
            return read_method(max_bytes)
        raise RuntimeError("Underlying stream does not support read()")

    def write(self, data: bytes) -> int:
        """
        Write bytes to the upgrade stream, forwarding to the underlying stream.
        """
        write_method = getattr(self._network_stream, "write", None)
        if callable(write_method):
            return write_method(data)
        raise RuntimeError("Underlying stream does not support write()")

    def close(self) -> None:
        """
        Close the upgrade stream and the underlying network stream if possible.
        """
        close_method = getattr(self._network_stream, "close", None)
        if callable(close_method):
            close_method()

    def start_tls(
        self,
        ssl_context: ssl.SSLContext,
        server_hostname: typing.Optional[str] = None,
    ) -> NetworkStream:
        """
        Start TLS on top of the current upgraded connection.

        Wraps the underlying network stream with TLS using the provided SSL context.
        """
        # If the underlying stream provides a start_tls method, prefer to use it.
        start_tls_method = getattr(self._network_stream, "start_tls", None)
        if callable(start_tls_method):
            return start_tls_method(ssl_context, server_hostname=server_hostname)

        # Otherwise, attempt a best-effort wrapping using Python sockets if available.
        raise NotImplementedError("start_tls is not implemented for this stream type")

    def get_extra_info(self, name: str, default: typing.Any = None) -> typing.Any:
        """
        Get extra information from the underlying stream, delegating if supported.
        """
        get_extra = getattr(self._network_stream, "get_extra_info", None)
        if callable(get_extra):
            return get_extra(name, default)
        return default